import sys
import queue

class Solution:
  def __init__(self):
    pass

  def solve(self):
    t = int(input())
    ans = ''
    for _ in range(t):
      n = int(input())
      dq = list(map(int, input().split()))

      if n == 0:
        ans += '-1
'
      else:
        ans += str(dq.pop(0)) + '\n'

    return ans

if __name__ == '__main__':
  sol = Solution()
  print(sol.solve())

