#include <iostream>
#include <deque>

int main() {
  std::ios_base::sync_with_stdio(false);
  std::cin.tie(NULL);

  int t;
  std::cin >> t;
  while (t-- > 0) {
    int n;
    std::cin >> n;

    if (n == 0) {
      std::cout << '-1' << '\n';
    } else {
      std::deque<int> dq;
      for (int i = 0; i < n; i++) {
        int x;
        std::cin >> x;
        dq.push_back(x);
      }

      std::cout << dq.front() << '\n';

      dq.pop_front();
    }
  }

  return 0;
}
